import React, { useEffect, useState } from "react";
import styled, { keyframes } from "styled-components";

/**
 * AuroraCurtain — northern-lights aurora splash.
 *
 * Soft flowing ribbons of green/teal/violet drift diagonally across a near-black
 * sky while subtle vertical streaks fall behind them, then the curtain fades to
 * reveal the page. SVG paths animated with CSS transforms + opacity pulses keep
 * the bundle small (no canvas, no extra deps).
 *
 * Total runtime ≈ 1.8s before onFinish fires.
 */

// ===== timing =====
const RIBBONS_IN_MS = 250;
const HOLD_MS = 1150;        // includes name fade-in
const FADE_MS = 400;         // bg + ribbons fade
const TOTAL_MS = RIBBONS_IN_MS + HOLD_MS + FADE_MS; // ~1800ms

// ===== palette =====
const BG = "#060914";
const C_TEAL = "#3FE0C5";
const C_GREEN = "#6CE3A6";
const C_VIOLET = "#8A6CFF";
const C_BLUE = "#4B6CFF";

// ===== keyframes =====
const drift = keyframes`
  0%   { transform: translate3d(-12%, 6%, 0) skewY(-8deg) scale(1.05); opacity: 0; }
  18%  { opacity: 1; }
  100% { transform: translate3d(8%, -4%, 0) skewY(-12deg) scale(1.12); opacity: 1; }
`;

const driftAlt = keyframes`
  0%   { transform: translate3d(10%, -4%, 0) skewY(10deg) scale(1.08); opacity: 0; }
  20%  { opacity: 1; }
  100% { transform: translate3d(-8%, 8%, 0) skewY(6deg) scale(1.15); opacity: 1; }
`;

const pulse = keyframes`
  0%   { opacity: 0.55; }
  50%  { opacity: 0.95; }
  100% { opacity: 0.55; }
`;

const streak = keyframes`
  0%   { transform: translateY(-60%) scaleY(0.4); opacity: 0; }
  20%  { opacity: 0.45; }
  70%  { opacity: 0.35; }
  100% { transform: translateY(60%) scaleY(1.4); opacity: 0; }
`;

const dashFlow = keyframes`
  0%   { stroke-dashoffset: 600; }
  100% { stroke-dashoffset: 0; }
`;

const titleReveal = keyframes`
  0%   { opacity: 0; transform: translateY(8px); letter-spacing: 0.04em; }
  100% { opacity: 1; transform: translateY(0);   letter-spacing: 0.08em; }
`;

// ===== styled =====
const Wrap = styled.div`
  position: fixed;
  inset: 0;
  z-index: 9999;
  pointer-events: none;
  background: radial-gradient(
      ellipse 120% 80% at 50% 110%,
      #0c1a30 0%,
      ${BG} 55%,
      #02040a 100%
    );
  overflow: hidden;
  transition: opacity 450ms ease;
  opacity: ${({ $fade }) => ($fade ? 0 : 1)};
`;

// Pinprick starfield — drawn with a tiny radial-gradient pattern so we don't
// spawn dozens of DOM nodes.
const Stars = styled.div`
  position: absolute;
  inset: 0;
  background-image:
    radial-gradient(circle at 12% 28%, rgba(255,255,255,0.55) 0.6px, transparent 1px),
    radial-gradient(circle at 78% 14%, rgba(255,255,255,0.40) 0.6px, transparent 1px),
    radial-gradient(circle at 36% 70%, rgba(255,255,255,0.45) 0.6px, transparent 1px),
    radial-gradient(circle at 90% 62%, rgba(255,255,255,0.30) 0.6px, transparent 1px),
    radial-gradient(circle at 22% 86%, rgba(255,255,255,0.35) 0.6px, transparent 1px),
    radial-gradient(circle at 60% 40%, rgba(255,255,255,0.25) 0.6px, transparent 1px);
  opacity: 0.7;
`;

const Sky = styled.svg`
  position: absolute;
  inset: 0;
  width: 100%;
  height: 100%;
  mix-blend-mode: screen;
`;

// Vertical light streaks behind the ribbons — subtle falling glow lines.
const StreakLayer = styled.div`
  position: absolute;
  inset: 0;
  mix-blend-mode: screen;
  pointer-events: none;
`;

const Streak = styled.span`
  position: absolute;
  top: 0;
  width: 1.5px;
  height: 38%;
  background: linear-gradient(
    to bottom,
    rgba(140, 220, 255, 0) 0%,
    rgba(140, 220, 255, 0.7) 45%,
    rgba(140, 220, 255, 0) 100%
  );
  filter: blur(0.4px);
  animation: ${streak} ${({ $dur }) => $dur}ms cubic-bezier(0.45, 0.05, 0.55, 1)
    ${({ $delay }) => $delay}ms infinite;
  left: ${({ $left }) => $left}%;
`;

const Title = styled.div`
  position: absolute;
  inset: 0;
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
  gap: 16px;
  z-index: 2;
  text-align: center;
  font-family: -apple-system, "Inter", "Helvetica Neue", Arial, sans-serif;

  .name {
    font-size: clamp(28px, 5.2vw, 56px);
    font-weight: 900;
    letter-spacing: 0.08em;
    color: #f1f6ff;
    text-shadow:
      0 0 14px rgba(63, 224, 197, 0.45),
      0 0 28px rgba(138, 108, 255, 0.35);
    animation: ${titleReveal} 700ms cubic-bezier(0.16, 1, 0.3, 1) 280ms both;

    span {
      color: ${C_TEAL};
    }
  }

  .tagline {
    font-family: "SF Mono", "JetBrains Mono", Menlo, Consolas, monospace;
    font-size: clamp(10px, 1.1vw, 12px);
    color: rgba(180, 200, 230, 0.78);
    letter-spacing: 0.32em;
    text-transform: uppercase;
    animation: ${titleReveal} 700ms cubic-bezier(0.16, 1, 0.3, 1) 440ms both;
  }
`;

// One ribbon = a soft SVG path with a vertical gradient stroke, drifting + pulsing.
const RibbonGroup = styled.g`
  transform-origin: 50% 50%;
  animation:
    ${({ $alt }) => ($alt ? driftAlt : drift)}
      ${({ $driftMs }) => $driftMs}ms ease-out ${({ $delay }) => $delay}ms both,
    ${pulse} ${({ $pulseMs }) => $pulseMs}ms ease-in-out
      ${({ $delay }) => $delay}ms infinite;
  filter: blur(${({ $blur }) => $blur}px);

  path {
    stroke-dasharray: 600 240;
    animation: ${dashFlow} ${({ $flowMs }) => $flowMs}ms linear
      ${({ $delay }) => $delay}ms infinite;
  }
`;

const AuroraCurtain = ({ onFinish }) => {
  const [fade, setFade] = useState(false);
  const [done, setDone] = useState(false);

  useEffect(() => {
    const fadeT = setTimeout(() => setFade(true), RIBBONS_IN_MS + HOLD_MS);
    const doneT = setTimeout(() => {
      setDone(true);
      if (onFinish) onFinish();
    }, TOTAL_MS);
    return () => {
      clearTimeout(fadeT);
      clearTimeout(doneT);
    };
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  if (done) return null;

  // Ribbon paths — broad horizontal S-curves that fill the sky.
  // Designed against a 1000×600 viewBox so they scale with the screen.
  return (
    <Wrap $fade={fade}>
      <Stars />

      <StreakLayer>
        <Streak $left={8}  $dur={2400} $delay={0} />
        <Streak $left={24} $dur={2800} $delay={420} />
        <Streak $left={47} $dur={2600} $delay={180} />
        <Streak $left={63} $dur={3000} $delay={620} />
        <Streak $left={81} $dur={2500} $delay={300} />
        <Streak $left={92} $dur={2700} $delay={520} />
      </StreakLayer>

      <Sky viewBox="0 0 1000 600" preserveAspectRatio="none">
        <defs>
          <linearGradient id="ag-teal" x1="0" y1="0" x2="0" y2="1">
            <stop offset="0%"  stopColor={C_TEAL}  stopOpacity="0" />
            <stop offset="50%" stopColor={C_TEAL}  stopOpacity="0.9" />
            <stop offset="100%" stopColor={C_TEAL} stopOpacity="0" />
          </linearGradient>
          <linearGradient id="ag-green" x1="0" y1="0" x2="0" y2="1">
            <stop offset="0%"  stopColor={C_GREEN} stopOpacity="0" />
            <stop offset="50%" stopColor={C_GREEN} stopOpacity="0.85" />
            <stop offset="100%" stopColor={C_GREEN} stopOpacity="0" />
          </linearGradient>
          <linearGradient id="ag-violet" x1="0" y1="0" x2="0" y2="1">
            <stop offset="0%"   stopColor={C_VIOLET} stopOpacity="0" />
            <stop offset="50%"  stopColor={C_VIOLET} stopOpacity="0.85" />
            <stop offset="100%" stopColor={C_VIOLET} stopOpacity="0" />
          </linearGradient>
          <linearGradient id="ag-blue" x1="0" y1="0" x2="0" y2="1">
            <stop offset="0%"   stopColor={C_BLUE} stopOpacity="0" />
            <stop offset="50%"  stopColor={C_BLUE} stopOpacity="0.7" />
            <stop offset="100%" stopColor={C_BLUE} stopOpacity="0" />
          </linearGradient>
        </defs>

        {/* Back-most violet/blue veil — broadest, blurriest */}
        <RibbonGroup
          $alt={false}
          $driftMs={1800}
          $pulseMs={1700}
          $flowMs={3200}
          $delay={0}
          $blur={6}
        >
          <path
            d="M -120 320 C 180 180, 420 460, 700 260 S 1040 220, 1180 320"
            fill="none"
            stroke="url(#ag-violet)"
            strokeWidth="120"
            strokeLinecap="round"
          />
        </RibbonGroup>

        <RibbonGroup
          $alt={true}
          $driftMs={1800}
          $pulseMs={1500}
          $flowMs={2800}
          $delay={60}
          $blur={4}
        >
          <path
            d="M -100 250 C 200 380, 460 160, 740 320 S 980 380, 1120 240"
            fill="none"
            stroke="url(#ag-blue)"
            strokeWidth="90"
            strokeLinecap="round"
          />
        </RibbonGroup>

        {/* Mid teal sheet — the signature aurora green-teal */}
        <RibbonGroup
          $alt={false}
          $driftMs={1700}
          $pulseMs={1300}
          $flowMs={2400}
          $delay={120}
          $blur={2.5}
        >
          <path
            d="M -120 360 C 220 220, 460 420, 720 280 S 1020 360, 1180 280"
            fill="none"
            stroke="url(#ag-teal)"
            strokeWidth="60"
            strokeLinecap="round"
          />
        </RibbonGroup>

        {/* Front-most crisp green ribbon — narrowest, sharpest */}
        <RibbonGroup
          $alt={true}
          $driftMs={1600}
          $pulseMs={1100}
          $flowMs={2000}
          $delay={180}
          $blur={1.2}
        >
          <path
            d="M -100 300 C 240 360, 480 200, 760 320 S 1000 280, 1140 360"
            fill="none"
            stroke="url(#ag-green)"
            strokeWidth="34"
            strokeLinecap="round"
          />
        </RibbonGroup>
      </Sky>

      <Title>
        <div className="name">
          DIBYAJYOTI<span>.</span>
        </div>
        <div className="tagline">Senior Software Engineer · London</div>
      </Title>
    </Wrap>
  );
};

export default AuroraCurtain;
